7876 /// Return true if undefined behavior would provably be executed on the path to
7877 /// OnPathTo if Root produced a posion result.  Note that this doesn't say
7878 /// anything about whether OnPathTo is actually executed or whether Root is
7879 /// actually poison.  This can be used to assess whether a new use of Root can
7880 /// be added at a location which is control equivalent with OnPathTo (such as
7881 /// immediately before it) without introducing UB which didn't previously
7882 /// exist.  Note that a false result conveys no information.
7883 bool llvm::mustExecuteUBIfPoisonOnPathTo(Instruction *Root,
7884                                          Instruction *OnPathTo,
7885                                          DominatorTree *DT) {
7886   // Basic approach is to assume Root is poison, propagate poison forward
7887   // through all users we can easily track, and then check whether any of those
7888   // users are provable UB and must execute before out exiting block might
7889   // exit.
7890 
7891   // The set of all recursive users we've visited (which are assumed to all be
7892   // poison because of said visit)
7893   SmallPtrSet<const Value *, 16> KnownPoison;
7894   SmallVector<const Instruction*, 16> Worklist;
7895   Worklist.push_back(Root);
7896   while (!Worklist.empty()) {
7897     const Instruction *I = Worklist.pop_back_val();
7898 
7899     // If we know this must trigger UB on a path leading our target.
7900     if (mustTriggerUB(I, KnownPoison) && DT->dominates(I, OnPathTo))
7901       return true;
7902 
7903     // If we can't analyze propagation through this instruction, just skip it
7904     // and transitive users.  Safe as false is a conservative result.
7905     if (I != Root && !any_of(I->operands(), [&KnownPoison](const Use &U) {
7906           return KnownPoison.contains(U) && propagatesPoison(U);
7907         }))
7908       continue;
7909 
7910     if (KnownPoison.insert(I).second)
7911       for (const User *User : I->users())
7912         Worklist.push_back(cast<Instruction>(User));
7913   }
7914 
7915   // Might be non-UB, or might have a path we couldn't prove must execute on
7916   // way to exiting bb.
7917   return false;
7918 }
