7933 bool llvm::isGuaranteedToTransferExecutionToSuccessor(const Instruction *I) {
7934   // Note: An atomic operation isn't guaranteed to return in a reasonable amount
7935   // of time because it's possible for another thread to interfere with it for an
7936   // arbitrary length of time, but programs aren't allowed to rely on that.
7937 
7938   // If there is no successor, then execution can't transfer to it.
7939   if (isa<ReturnInst>(I))
7940     return false;
7941   if (isa<UnreachableInst>(I))
7942     return false;
7943 
7944   // Note: Do not add new checks here; instead, change Instruction::mayThrow or
7945   // Instruction::willReturn.
7946   //
7947   // FIXME: Move this check into Instruction::willReturn.
7948   if (isa<CatchPadInst>(I)) {
7949     switch (classifyEHPersonality(I->getFunction()->getPersonalityFn())) {
7950     default:
7951       // A catchpad may invoke exception object constructors and such, which
7952       // in some languages can be arbitrary code, so be conservative by default.
7953       return false;
7954     case EHPersonality::CoreCLR:
7955       // For CoreCLR, it just involves a type test.
7956       return true;
7957     }
7958   }
7959 
7960   // An instruction that returns without throwing must transfer control flow
7961   // to a successor.
7962   return !I->mayThrow() && I->willReturn();
7963 }
