7694 static bool isGuaranteedNotToBeUndefOrPoison(
7695     const Value *V, AssumptionCache *AC, const Instruction *CtxI,
7696     const DominatorTree *DT, unsigned Depth, UndefPoisonKind Kind) {
7697   if (Depth >= MaxAnalysisRecursionDepth)
7698     return false;
7699 
7700   if (isa<MetadataAsValue>(V))
7701     return false;
7702 
7703   if (const auto *A = dyn_cast<Argument>(V)) {
7704     if (A->hasAttribute(Attribute::NoUndef) ||
7705         A->hasAttribute(Attribute::Dereferenceable) ||
7706         A->hasAttribute(Attribute::DereferenceableOrNull))
7707       return true;
7708   }
7709 
7710   if (auto *C = dyn_cast<Constant>(V)) {
7711     if (isa<PoisonValue>(C))
7712       return !includesPoison(Kind);
7713 
7714     if (isa<UndefValue>(C))
7715       return !includesUndef(Kind);
7716 
7717     if (isa<ConstantInt>(C) || isa<GlobalVariable>(C) || isa<ConstantFP>(C) ||
7718         isa<ConstantPointerNull>(C) || isa<Function>(C))
7719       return true;
7720 
7721     if (C->getType()->isVectorTy()) {
7722       if (isa<ConstantExpr>(C)) {
7723         // Scalable vectors can use a ConstantExpr to build a splat.
7724         if (Constant *SplatC = C->getSplatValue())
7725           if (isa<ConstantInt>(SplatC) || isa<ConstantFP>(SplatC))
7726             return true;
7727       } else {
7728         if (includesUndef(Kind) && C->containsUndefElement())
7729           return false;
7730         if (includesPoison(Kind) && C->containsPoisonElement())
7731           return false;
7732         return !C->containsConstantExpression();
7733       }
7734     }
7735   }
7736 
7737   // Strip cast operations from a pointer value.
7738   // Note that stripPointerCastsSameRepresentation can strip off getelementptr
7739   // inbounds with zero offset. To guarantee that the result isn't poison, the
7740   // stripped pointer is checked as it has to be pointing into an allocated
7741   // object or be null `null` to ensure `inbounds` getelement pointers with a
7742   // zero offset could not produce poison.
7743   // It can strip off addrspacecast that do not change bit representation as
7744   // well. We believe that such addrspacecast is equivalent to no-op.
7745   auto *StrippedV = V->stripPointerCastsSameRepresentation();
7746   if (isa<AllocaInst>(StrippedV) || isa<GlobalVariable>(StrippedV) ||
7747       isa<Function>(StrippedV) || isa<ConstantPointerNull>(StrippedV))
7748     return true;
7749 
7750   auto OpCheck = [&](const Value *V) {
7751     return isGuaranteedNotToBeUndefOrPoison(V, AC, CtxI, DT, Depth + 1, Kind);
7752   };
7753 
7754   if (auto *Opr = dyn_cast<Operator>(V)) {
7755     // If the value is a freeze instruction, then it can never
7756     // be undef or poison.
7757     if (isa<FreezeInst>(V))
7758       return true;
7759 
7760     if (const auto *CB = dyn_cast<CallBase>(V)) {
7761       if (CB->hasRetAttr(Attribute::NoUndef) ||
7762           CB->hasRetAttr(Attribute::Dereferenceable) ||
7763           CB->hasRetAttr(Attribute::DereferenceableOrNull))
7764         return true;
7765     }
7766 
7767     if (!::canCreateUndefOrPoison(Opr, Kind,
7768                                   /*ConsiderFlagsAndMetadata=*/true)) {
7769       if (const auto *PN = dyn_cast<PHINode>(V)) {
7770         unsigned Num = PN->getNumIncomingValues();
7771         bool IsWellDefined = true;
7772         for (unsigned i = 0; i < Num; ++i) {
7773           if (PN == PN->getIncomingValue(i))
7774             continue;
7775           auto *TI = PN->getIncomingBlock(i)->getTerminator();
7776           if (!isGuaranteedNotToBeUndefOrPoison(PN->getIncomingValue(i), AC, TI,
7777                                                 DT, Depth + 1, Kind)) {
7778             IsWellDefined = false;
7779             break;
7780           }
7781         }
7782         if (IsWellDefined)
7783           return true;
7784       } else if (auto *Splat = isa<ShuffleVectorInst>(Opr) ? getSplatValue(Opr)
7785                                                            : nullptr) {
7786         // For splats we only need to check the value being splatted.
7787         if (OpCheck(Splat))
