7812   // If V is used as a branch condition before reaching CtxI, V cannot be
7813   // undef or poison.
7814   //   br V, BB1, BB2
7815   // BB1:
7816   //   CtxI ; V cannot be undef or poison here
7817   auto *Dominator = DNode->getIDom();
