7826         if (BI->isConditional())
7827           Cond = BI->getCondition();
7828       } else if (auto SI = dyn_cast_or_null<SwitchInst>(TI)) {
7829         Cond = SI->getCondition();
7830       }
7831 
7832       if (Cond) {
7833         if (Cond == V)
7834           return true;
7835         else if (!includesUndef(Kind) && isa<Operator>(Cond)) {
7836           // For poison, we can analyze further
7837           auto *Opr = cast<Operator>(Cond);
7838           if (any_of(Opr->operands(), [V](const Use &U) {
7839                 return V == U && propagatesPoison(U);
7840               }))
7841             return true;
7842         }
7843       }
7844 
7845       Dominator = Dominator->getIDom();
7846     }
7847 
7848   if (AC && getKnowledgeValidInContext(V, {Attribute::NoUndef}, *AC, CtxI, DT))
7849     return true;
7850 
7851   return false;
7852 }
